import{AssetCatalogSchema as h,emptyCatalog as p}from"./types.js";export class AssetCatalogManager{static mergeCatalog(e,t){const s={characters:[...e.characters],scenes:[...e.scenes],props:[...e.props]},o=["characters","scenes","props"];for(const n of o){const c=t.catalog[n];for(const r of c){const a=s[n].findIndex(i=>AssetCatalogManager.isMatch(r,i));a>=0?s[n][a]=AssetCatalogManager.mergeAsset(s[n][a],r):s[n].push({...r})}}return s}static serializeCatalog(e){return JSON.stringify(e,null,2)}static parseCatalog(e){try{const t=JSON.parse(e),s=h.safeParse(t);if(s.success)return s.data}catch{}return p()}static normalizeName(e){return e.trim().toLowerCase().replace(/[\u3000\s]+/g," ").trim().replace(/[·・\.\,\;\:\!\?\。\，\、\；\：\！\？\"\"''\'\（\）\【\】\《\》]/g,"").replace(/\s+/g,"").trim()}static generateNicknameVariants(e){const t=new Set,s=AssetCatalogManager.normalizeName(e);if(!s)return[];if(!/^[\u4e00-\u9fff]+$/.test(s))return[];if((s.startsWith("\u5C0F")||s.startsWith("\u8001"))&&s.length>=2){const n=s.slice(1,2);t.add(n)}if(s.length>=2&&s.length<=3){const n=s[0];s.length===2&&(s[0]==="\u5C0F"||s[0]==="\u8001")||(t.add("\u5C0F"+n),t.add("\u8001"+n))}return[...t]}static extractSurnameKey(e){const t=AssetCatalogManager.normalizeName(e);if(!t||!/^[\u4e00-\u9fff]+$/.test(t))return null;if((t.startsWith("\u5C0F")||t.startsWith("\u8001"))&&t.length>=2)return t[1];const o=["\u54E5","\u59D0","\u603B","\u6559\u6388","\u8001\u5E08","\u5E08\u5085","\u5148\u751F","\u5973\u58EB","\u540C\u5B66","\u533B\u751F","\u535A\u58EB"];for(const n of o)if(t.endsWith(n)&&t.length>n.length)return t.slice(0,t.length-n.length);return t.length>=2&&t.length<=3?t[0]:null}static isMatch(e,t){const s=AssetCatalogManager.allNames(e),o=AssetCatalogManager.allNames(t);for(const n of s)for(const c of o)if(n===c)return!0;if(e.kind==="character"&&t.kind==="character"){const n=a=>{const i=AssetCatalogManager.normalizeName(a);return!i||!/^[\u4e00-\u9fff]+$/.test(i)||i.length>3?!1:i.startsWith("\u5C0F")||i.startsWith("\u8001")?!0:["\u54E5","\u59D0","\u603B","\u6559\u6388","\u8001\u5E08","\u5E08\u5085","\u5148\u751F","\u5973\u58EB","\u540C\u5B66","\u533B\u751F","\u535A\u58EB"].some(l=>i.endsWith(l)&&i.length>l.length)},c=n(e.name)||e.aliases.some(n),r=n(t.name)||t.aliases.some(n);if(c!==r){const a=c?[e.name,...e.aliases]:[t.name,...t.aliases],i=c?[t.name,...t.aliases]:[e.name,...e.aliases];for(const f of a){const l=AssetCatalogManager.extractSurnameKey(f);if(l)for(const u of i){const m=AssetCatalogManager.extractSurnameKey(u);if(m&&l===m)return!0}}}}return!1}static allNames(e){const s=[e.name,...e.aliases].map(r=>AssetCatalogManager.normalizeName(r)).filter(r=>r.length>0),o=[];for(const r of s)for(const a of AssetCatalogManager.generateNicknameVariants(r))a.length>0&&o.push(a);const n=new Set,c=[];for(const r of[...s,...o])n.has(r)||(n.add(r),c.push(r));return c}static mergeAsset(e,t){const s=e.name,o=[...e.aliases,...t.aliases],n=new Set,c=[];for(const r of o){const a=r.trim().toLowerCase();a!==s.trim().toLowerCase()&&(n.has(a)||(n.add(a),c.push(r)))}return{id:e.id,kind:e.kind,name:e.name,aliases:c,description:t.description.trim().length>0?t.description:e.description,firstChapter:e.firstChapter,lastChapter:Math.max(e.lastChapter,t.lastChapter),attributes:{...e.attributes,...t.attributes},appearanceCount:e.appearanceCount+1}}}
